        "promptStarter": "Crea una imagen de un atleta saltando sobre un obstáculo, usando una foto de referencia para la pose y dos estilos visuales distintos.",
        "promptExamples": [
                {
                        "title": "Prompt con imagen guía",
                        "prompt": "Un bailarín clásico en pose de arabesque, fondo de teatro, estilo realista, usando imagen guía de pose."
                },
                {
                        "title": "Prompt para fondo complejo",
                        "prompt": "Un bosque encantado con caminos sinuosos, composición guiada por un boceto, estilo arte digital."
                },
                {
                        "title": "Prompt para control de perspectiva",
                        "prompt": "Un auto deportivo visto desde arriba, usando mapa de profundidad como guía, estilo realista."
                }
        ]
