        "mejorar-resultados": {
        "id": "mejorar-resultados",
        "title": "Cómo mejorar resultados y evitar errores comunes",
        "moduleTitle": "Herramientas para negocios",
        "durationMinutes": 10,
        "summary": "Aprende técnicas para refinar tus prompts, corregir errores frecuentes y obtener mejores resultados en la aplicación de IA en negocios.",
        "objectives": [
                "Identificar errores comunes en prompts para negocios.",
                "Aplicar técnicas de iteración y ajuste.",
                "Obtener soluciones más alineadas con las necesidades empresariales."
        ],
        "sections": [
                {
                        "heading": "Errores frecuentes y cómo solucionarlos",
                        "content": "Errores típicos: prompts ambiguos, pedir soluciones demasiado generales, no especificar el contexto del negocio. Solución: revisa tu prompt, añade detalles y enfócate en el objetivo empresarial."
                },
                {
                        "heading": "Iterar y ajustar para mejorar",
                        "content": "Genera la solución, analiza el resultado y ajusta el prompt: cambia el enfoque, añade o elimina detalles, prueba diferentes herramientas. La iteración es clave para obtener el resultado ideal."
                },
                {
                        "heading": "Consejos de expertos",
                        "content": "Guarda tus mejores prompts como plantillas, revisa ejemplos y aprende de la comunidad. No temas experimentar y pedir feedback a otros empresarios."
                }
        ],
        "activity": "Elige una solución IA generada que no te convenza. Ajusta el prompt al menos dos veces para mejorar el resultado y documenta los cambios.",
        "deliverable": "Secuencia de 3 soluciones (original + 2 iteraciones) con explicación de los cambios y mejoras logradas.",
        "checklist": [
                "Identifiqué y corregí errores en mis prompts empresariales.",
                "Iteré al menos dos veces para mejorar el resultado.",
                "Documenté el proceso de mejora."
        ],
        "promptStarter": "Genera una propuesta para mejorar la atención al cliente. Si el resultado no es satisfactorio, ajusta el prompt para enfocarlo en canales digitales y luego en personalización.",
        "promptExamples": [
                {
                        "title": "Prompt original",
                        "prompt": "Mejorar la atención al cliente en una tienda online."
                },
                {
                        "title": "Primera iteración",
                        "prompt": "Propón soluciones digitales para mejorar la atención al cliente en una tienda online."
                },
                {
                        "title": "Segunda iteración",
                        "prompt": "Sugiere cómo personalizar la atención al cliente usando IA y datos de comportamiento."
                }
        ]
},
